mapper.select:
/* MarketingMapper.getMarketingSendTarget */ SELECT SEND.SEND_DIVISION ,SEND.CONTRACT_NUM ,SEND.USERID ,SEND.TEMPLATE_ID ,SEND.MOBILE_NO ,SEND.STRT_DTTM ,SUBSTR(SEND.STRT_DTTM, 1, 4) || '-' || SUBSTR(SEND.STRT_DTTM, 5, 2) || '-' || SUBSTR(SEND.STRT_DTTM, 7, 2) AS AGR_DT ,TM.MSG_TYPE ,TM.CALLBACK AS SEND_NUMBER ,TM.SUBJECT ,TM.TEXT AS SEND_MESSAGE ,TM.EXPIRE_HOUR * 60 * 60 AS EXPIRE_TIME ,COUNT(1) OVER() AS TOTAL_COUNT ,ROWNUM AS RN ,TO_CHAR(TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDD') || '100000', 'YYYYMMDDHH24MISS') + ((1/24/60) * TRUNC((ROWNUM - 1) / 100) * 10), 'YYYYMMDDHH24MISS') AS REQUEST_TIME FROM ( -- 홈페이지 발송대상 SELECT 'MCP' AS SEND_DIVISION ,'' AS CONTRACT_NUM ,A.USERID ,2 AS TEMPLATE_ID ,B.MOBILE_NO ,A.STRT_DTTM AS STRT_DTTM FROM (SELECT USERID ,MIN(STRT_DTTM) AS STRT_DTTM FROM MCP_MRKT_HIST@DL_MCP WHERE AGR_YN ='Y' AND TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') BETWEEN STRT_DTTM AND END_DTTM GROUP BY USERID ) A , MCP_USER@DL_MCP B WHERE A.USERID = B.USERID AND B.STATUS <> '3' AND B.AUTH_CODE = 'USER_ROLE' AND EXTRACT(MONTH FROM TO_DATE(A.STRT_DTTM, 'YYYYMMDDHH24MISS')) = EXTRACT(MONTH FROM ADD_MONTHS(SYSDATE, 1)) AND EXTRACT(YEAR FROM TO_DATE(A.STRT_DTTM, 'YYYYMMDDHH24MISS')) != EXTRACT(YEAR FROM ADD_MONTHS(SYSDATE, 1)) AND MOD(EXTRACT(YEAR FROM TO_DATE(A.STRT_DTTM, 'YYYYMMDDHH24MISS')), 2) = MOD(EXTRACT(YEAR FROM ADD_MONTHS(SYSDATE, 1)), 2)
UNION ALL
-- M전산 발송대상 SELECT 'MSP' AS SEND_DIVISION ,A.CONTRACT_NUM AS CONTRACT_NUM ,'' AS USERID ,1 AS TEMPLATE_ID ,B.SUBSCRIBER_NO AS MOBILE_NO ,A.STRT_DTTM FROM MSP_MRKT_AGR_MGMT A, MSP_JUO_SUB_INFO B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND B.SUB_STATUS <> 'C' AND A.AGR_YN = 'Y' AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN A.STRT_DTTM AND A.END_DTTM AND EXTRACT(MONTH FROM TO_DATE(A.STRT_DTTM, 'YYYYMMDDHH24MISS')) = EXTRACT(MONTH FROM ADD_MONTHS(SYSDATE, 1)) AND EXTRACT(YEAR FROM TO_DATE(A.STRT_DTTM, 'YYYYMMDDHH24MISS')) != EXTRACT(YEAR FROM ADD_MONTHS(SYSDATE, 1)) AND MOD(EXTRACT(YEAR FROM TO_DATE(A.STRT_DTTM, 'YYYYMMDDHH24MISS')), 2) = MOD(EXTRACT(YEAR FROM ADD_MONTHS(SYSDATE, 1)), 2) ) SEND, MSP_SMS_TEMPLATE_MST TM WHERE SEND.TEMPLATE_ID = TM.TEMPLATE_ID

mapper.insert:

	SELECT SMS_SEQ.NEXTVAL AS mseq
	FROM   DUAL

/* MarketingMapper.insertMsgQueue */
INSERT INTO MSG_QUEUE (
	 MSEQ			/* Sequence		*/
	,MSG_TYPE		/* 1:SMS 2:SMS URL 3:MMS 4:MMS URL	*/
	,DSTADDR		/* 수신자 번호	*/
	,CALLBACK		/* 발신자 번호	*/
	,SUBJECT		/* 제목 		*/
	,TEXT			/* 전송메시지	*/
	,EXPIRETIME		/* 유효시간		*/
	,REQUEST_TIME	/* 발송요청시간	*/
	,OPT_ID			/* SMS TEMPLATE ID	*/
)
VALUES (
	 #{mseq}
	,#{msgType}
	,#{mobileNo}
	,#{sendNumber}
	,#{subject}
	,#{sendMessage}
	,#{expireTime}
	,TO_DATE(#{requestTime}, 'YYYYMMDDHH24MISS')
	,#{templateId}
)

/* MarketingMapper.insertSmsSendMst */
INSERT INTO MSP_SMS_SEND_MST (
	 SEND_SEQ			/* 일련번호	*/
	,SEND_DIVISION		/* 발송구분(MCP:홈페이지,MSP:M전산) */
	,CONTRACT_NUM		/* 계약번호 */
	,PORTAL_USER_ID		/* 홈페이지사용자ID */
	,TEMPLATE_ID		/* SMS Template ID */
	,MSEQ				/* SMS일련번호 */
	,SEND_REQ_DTTM		/* 발송요청일시 */
	,REGST_ID			/* 등록자ID */
	,REGST_DTTM			/* 등록일시 */
	,RVISN_ID			/* 수정자ID */
	,RVISN_DTTM			/* 수정일시 */
)
VALUES (
	 SMS_SEND_SEQ.NEXTVAL
	,#{sendDivision}
	,#{contractNum}
	,#{userid}
	,#{templateId}
	,#{mseq}
	,#{requestTime}
	,#{reqId}
	,SYSDATE
	,#{reqId}
	,SYSDATE
)

mapper.update:
/* MarketingMapper.updateSmsSendMst */
UPDATE  MSP_SMS_SEND_MST
SET     SEND_CNT = SEND_CNT + 1
        , MSEQ = #{mseq}
        , SEND_REQ_DTTM = #{requestTime}
        , RVISN_ID = #{reqId}
        , RVISN_DTTM = SYSDATE
WHERE   SEND_SEQ = #{sendSeq}
